#!/usr/bin/env bash
# diff_step2_baseline.sh — compare a freshly-regenerated baseline against the
# locked manifest, IGNORING the provenance "Generated by:" line (which records
# argv[0] and is therefore invocation-path-sensitive, not a code difference).
# Behavior-preserving refactors must produce a clean diff here.
# Usage: ./benchmarks/diff_step2_baseline.sh <locked_dir> <new_dir>
set -uo pipefail
LOCKED="${1:-/tmp/step2_baseline}"; NEW="${2:-/tmp/step2_after}"
NORM='s# \* Generated by:.*gen_radix.exe# * Generated by: gen_radix.exe#'
man(){ ( cd "$1" && for f in *.c; do h=$(sed "$NORM" "$f" | sha256sum | cut -d' ' -f1); echo "$h  $f"; done | sort -k2 ); }
man "$LOCKED" > /tmp/.b2_locked.man
man "$NEW"    > /tmp/.b2_new.man
if diff /tmp/.b2_locked.man /tmp/.b2_new.man >/dev/null 2>&1; then
  n=$(wc -l < /tmp/.b2_locked.man)
  echo "[IDENTICAL: $n/$n codelets byte-for-byte (provenance-normalized)]"; exit 0
else
  echo "[DIFFERS — behavior-preserving refactor should NOT change emitted code:]"
  diff /tmp/.b2_locked.man /tmp/.b2_new.man | head -20; exit 1
fi
